#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d",&N,&Q);
        int divs[13]; int dcnt=0;
        for(int i=1;i<=N;i++) if(N%i==0) divs[dcnt++]=i;
        for(int qi=0;qi<Q;qi++){
            int type,K; scanf("%d %d",&type,&K);
            int ans=0;
            if(type==1){
                for(int i=0;i<dcnt;i++) if(K%divs[i]==0) ans++;
            }else if(type==2){
                for(int i=0;i<dcnt;i++) if(divs[i]%K==0) ans++;
            }else{ // type 3
                int cnt2=0;
                for(int i=0;i<dcnt;i++) if(divs[i]%K==0) cnt2++;
                ans=dcnt-cnt2;
            }
            printf("%d\n",ans);
        }
    }
    return 0;
}

